#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B) {
    // Use raw pointers for maximum performance.
    double *a = A.data();
    double *b = B.data();

    // The factor 1/3 is constant for all updates.
    constexpr double inv3 = 0.33333;

    // A small helper lambda to perform a single Jacobi pass.
    auto jacobi_step = [&](double *src, double *dst) {
        // Parallelize i loop with SIMD enabled.
        #pragma omp parallel for simd schedule(static)
        for (std::size_t i = 1; i < static_cast<std::size_t>(n) - 1; ++i) {
            dst[i] = inv3 * (src[i-1] + src[i] + src[i+1]);
        }
    };

    // Perform the requested number of T steps.
    for (int t = 0; t < tsteps; ++t) {
        // B is computed from current A.
        jacobi_step(a, b);
        // A is updated from new B.
        jacobi_step(b, a);
    }
}
