/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A) {

    // Pointer‑style access for speed
    double (*Cptr)[n] = reinterpret_cast<double (*)[n]>(C.data());
    double (*Aptr)[m] = reinterpret_cast<double (*)[m]>(A.data());

    /* Parallelise the outer most loop.  Each iteration works on a
       separate row of C and therefore can run independently */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        /* Pre‑scale the lower triangle of the current row */
        for (int j = 0; j <= i; ++j)
            Cptr[i][j] *= beta;

        /* Main kernel: accumulate rank‑m terms */
        for (int k = 0; k < m; ++k) {
            double aik = Aptr[i][k] * alpha;          // pre‑compute
            for (int j = 0; j <= i; ++j)
                Cptr[i][j] += aik * Aptr[j][k];
        }
    }
}
