symm:
```cpp
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    // Collapse the two outer loops and use parallel for.
    // Each thread works on a distinct set of rows i, then all columns j.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        // Pointers to the current row of A and B for faster access
        double const *Ai  = A[i].data();
        double const *Bi  = B[i].data();
        double *Ci = C[i].data();

        for (int j = 0; j < n; ++j) {
            double temp2 = 0.0;
            double bij   = Bi[j];
            double aii   = Ai[i];

            // First loop over k < i
            for (int k = 0; k < i; ++k) {
                double aik = Ai[k];
                double bk   = B[k][j];
                // Update C[k][j]
                C[k][j] += alpha * bij * aik;
                // Accumulate temp2
                temp2 += bk * aik;
            }
            // Final update of C[i][j]
            Ci[j] = beta * Ci[j] + alpha * bij * aii + alpha * temp2;
        }
    }
}
