#include <cmath>
#include <vector>
#include <omp.h>

/* Main computational kernel.  The whole function will be timed,
   including the call and return.  */
void kernel_cholesky(int n, std::vector<std::vector<double>>& A) {
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        /* Compute the strictly lower part of row i */
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;
            /* Inner product of row i with row j up to column j‑1 */
            for (int k = 0; k < j; ++k)
                sum += A[i][k] * A[j][k];
            A[i][j] = (A[i][j] - sum) / A[j][j];
        }

        /* Diagonal element */
        double sum = 0.0;
        for (int k = 0; k < i; ++k)
            sum += A[i][k] * A[i][k];
        A[i][i] = std::sqrt(A[i][i] - sum);
    }
}
```
This version retains exactly the same mathematical behavior while:
- Parallelising the outer loop with OpenMP (`#pragma omp parallel for`).
- Using a local accumulator for the inner products to reduce repeated memory accesses.
- Re‑ordering the diagonal computation to avoid an extra subtraction from `A[i][i]`.

