void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    // ---------- Mean ----------------------------------------------
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        for (int i = 0; i < n; ++i) {
            s += data[i][j];
        }
        mean[j] = s / n;
    }

    // ---------- Center data ----------------------------------------
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* const row = data[i].data();
        for (int j = 0; j < m; ++j) {
            row[j] -= mean[j];
        }
    }

    // ---------- Covariance matrix ----------------------------------
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double* const rowi = data[i].data();
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            // accumulate column-wise products
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            double c = sum / (n - 1.0);
            cov[i][j] = c;
            cov[j][i] = c;               // symmetry
        }
    }
