/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_2mm(int ni, int nj, int nk, int nl,
                double alpha,
                double beta,
                std::vector<std::vector<double>>& tmp,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D)
{
    /* --------------------------------------------------------------------
       1) Cache‑friendly matrix multiplication:   tmp = alpha * A * B
       -------------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        const double* Arow = A[i].data();
        double* tmpRow = tmp[i].data();
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            double* tmpPtr = &tmpRow[j];
            const double* brow;
            for (int k = 0; k < nk; ++k) {
                brow = B[k].data();
                sum += Arow[k] * brow[j];
            }
            tmpRow[j] = alpha * sum;
        }
    }

    /* --------------------------------------------------------------------
       2) Second multiplication with scaling:   D = beta * D + tmp * C
       -------------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* Drow = D[i].data();
        const double* tmpRow = tmp[i].data();
        for (int j = 0; j < nl; ++j) {
            double sum = Drow[j] * beta;
            const double* ccol = C[0].data() + j;   // column pointer
            for (int k = 0; k < nj; ++k) {
                sum += tmpRow[k] * ccol[k * nl];    // C[k][j]
            }
            Drow[j] = sum;
        }
    }
}
