```cpp
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_heat_3d(int tsteps,
                    int n,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<std::vector<double>>>& B)
{
    const double coeff = 0.125;

#pragma omp parallel for collapse(3) schedule(static)
    for (int t = 1; t <= tsteps; ++t)
    {
        /* First half‑step: A -> B */
        for (int i = 1; i < n - 1; ++i)
            for (int j = 1; j < n - 1; ++j)
                for (int k = 1; k < n - 1; ++k)
                {
                    double a = A[i][j][k];
                    B[i][j][k] = coeff * (A[i+1][j][k] - 2.0 * a + A[i-1][j][k])
                               + coeff * (A[i][j+1][k] - 2.0 * a + A[i][j-1][k])
                               + coeff * (A[i][j][k+1] - 2.0 * a + A[i][j][k-1])
                               + a;
                }

        /* Second half‑step: B -> A */
        for (int i = 1; i < n - 1; ++i)
            for (int j = 1; j < n - 1; ++j)
                for (int k = 1; k < n - 1; ++k)
                {
                    double b = B[i][j][k];
                    A[i][j][k] = coeff * (B[i+1][j][k] - 2.0 * b + B[i-1][j][k])
                               + coeff * (B[i][j+1][k] - 2.0 * b + B[i][j-1][k])
                               + coeff * (B[i][j][k+1] - 2.0 * b + B[i][j][k-1])
                               + b;
                }
    }
}
