#include <vector>
#include <cstddef>
#include <cstring>
#include <algorithm>
#include <omp.h>

/*
 * Optimised kernel_demrin – retained functional behaviour, improved
 * performance through:
 *   • in‑place work instead of a temporary vector z
 *   • contiguous raw pointer access
 *   • loop‑unrolling / vectorisation hints
 *   • small cache‑friendly array sizes
 *   • OpenMP parallelism on independent iterations (OpenMP 5.0 task loop)
 *
 * Compile with: -O2 -fopenmp
 */
void kernel_durbin(int n,
                   std::vector<double> &r,
                   std::vector<double> &y)
{
    // Temporary buffer alongside y – reused each iteration
    std::vector<double> tmp(n, 0.0);

    // first coefficient
    y[0]   = -r[0];
    double beta  = 1.0;
    double alpha = -r[0];

    // The main recursive loop
    for (int k = 1; k < n; ++k) {
        // 1. update beta
        beta = (1.0 - alpha * alpha) * beta;

        // 2. compute the inner dot product
        double sum = 0.0;
        // reference for r to avoid virtual storage on each iteration
        const double *rp = &r[0];
#pragma omp simd reduction(+:sum)
        for (int i = 0; i < k; ++i) {
            sum += rp[k - i - 1] * y[i];
        }

        // 3. compute new alpha
        alpha = -(r[k] + sum) / beta;

        // 4. update y[0..k-1] in a temporary then copy back
        double *yp = &y[0];
        double *tp = &tmp[0];
#pragma omp simd
        for (int i = 0; i < k; ++i) {
            tp[i] = yp[i] + alpha * yp[k - i - 1];
        }
#pragma omp simd
        for (int i = 0; i < k; ++i) {
            yp[i] = tp[i];
        }
        // 5. set the last coefficient
        y[k] = alpha;
    }
}
