#include <vector>
#include <omp.h>

/* Main computational kernel.  The function is timed as a whole,
   so all setup and cleanup work is included. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {
    /* Work on raw pointers for maximum locality */
    const double * const * Aptr = reinterpret_cast<const double * const *>(A.data());
    const double * xptr = x.data();
    double * yptr      = y.data();
    double * tmpptr    = tmp.data();

    /* Zero the output vector once */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j) yptr[j] = 0.0;

    /* Main loop – parallelized over rows of A */
    #pragma omp parallel for schedule(static) reduction(+:yptr[:n])
    for (int i = 0; i < m; ++i) {
        const double * Arow = Aptr[i];
        double sum = 0.0;

        /* (tmp[i] = A[i,:] · x) */
        for (int j = 0; j < n; ++j) sum += Arow[j] * xptr[j];
        tmpptr[i] = sum;          /* store for later (needed by caller) */

        /* y += A[i,:] * tmp[i]  */
        for (int j = 0; j < n; ++j) yptr[j] += Arow[j] * sum;
    }
}
