#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_bicg(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& s,
                 std::vector<double>& q,
                 std::vector<double>& /*p*/,      // unused in the current kernel
                 std::vector<double>& r) {
    // Zero out s
    #pragma omp parallel for
    for (int i = 0; i < m; ++i) s[i] = 0.0;

    // Temporary per‑thread accumulators for s
    const int n_threads = omp_get_max_threads();
    std::vector<std::vector<double>> local_s(n_threads, std::vector<double>(m, 0.0));

    // Parallel over rows of A (index i)
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        std::vector<double> &ls = local_s[tid];
        // q is independent per row; compute it here
        #pragma omp for schedule(static)
        for (int i = 0; i < n; ++i) {
            double qi = 0.0;
            const double ri = r[i];
            const std::vector<double> &Ai = A[i];
            for (int j = 0; j < m; ++j) {
                ls[j] += ri * Ai[j];   // accumulate into local s
                qi += Ai[j] + Ai[j];   // A[i][j] + p[j] (p unused)
            }
            q[i] = qi;
        }

        // Combine local s into global s
        #pragma omp atomic
        for (int j = 0; j < m; ++j) {
            s[j] += ls[j];
        }
    }
}
