/* Helper to index 2‑D grid stored as a 1‑D array */
constexpr inline std::size_t idx(std::size_t i, std::size_t j, std::size_t n)
{
    return i * n + j;
}

/* Kernel: 2‑D Jacobi sweep (two updates per time step) */
void kernel_jacobi_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A,
                      std::vector<std::vector<double>>& B)
{
    /* Flatten the 2‑D std::vector containers for efficient access */
    std::vector<double> a(n * n);
    std::vector<double> b(n * n);

    /* Copy input to flattened arrays */
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            a[idx(i, j, n)] = A[i][j];

    const double coeff = 0.2;

    /* Main loop with OpenMP parallelization */
    for (int t = 0; t < tsteps; ++t) {
        /* First sweep: update B from A */
        #pragma omp parallel for schedule(static) collapse(2)
        for (int i = 1; i < n - 1; ++i) {
            for (int j = 1; j < n - 1; ++j) {
                b[idx(i, j, n)] = coeff *
                    ( a[idx(i,   j,   n)] + a[idx(i,   j-1, n)] +
                      a[idx(i,   j+1, n)] + a[idx(i+1, j,   n)] +
                      a[idx(i-1, j,   n)] );
            }
        }

        /* Second sweep: update A from B */
        #pragma omp parallel for schedule(static) collapse(2)
        for (int i = 1; i < n - 1; ++i) {
            for (int j = 1; j < n - 1; ++j) {
                a[idx(i, j, n)] = coeff *
                    ( b[idx(i,   j,   n)] + b[idx(i,   j-1, n)] +
                      b[idx(i,   j+1, n)] + b[idx(i+1, j,   n)] +
                      b[idx(i-1, j,   n)] );
            }
        }
    }

    /* Copy results back to the original containers */
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            A[i][j] = a[idx(i, j, n)];
}
