/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_seidel_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A) {
    // Flatten the 2‑D std::vector to a 1‑D buffer for better cache utilisation
    // We keep the original vector for API compatibility
    const int N = n * n;
    std::vector<double> flat(N);
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            flat[i * n + j] = A[i][j];

    const double inv9 = 1.0 / 9.0;
    const int stride = n;

    // Main time‑stepping loop
    for (int t = 0; t < tsteps; ++t) {
        // Parallelise over the i dimension, each thread works on a different row stripe
        #pragma omp parallel for schedule(static)
        for (int i = 1; i <= n - 2; ++i) {
            int base = i * stride;
            int prev = (i - 1) * stride;
            int next = (i + 1) * stride;
            for (int j = 1; j <= n - 2; ++j) {
                // Row‑major flattening gives direct indexing
                const double sum =
                    flat[prev + j - 1] + flat[prev + j] + flat[prev + j + 1] +
                    flat[base + j - 1] + flat[base + j] + flat[base + j + 1] +
                    flat[next + j - 1] + flat[next + j] + flat[next + j + 1];
                flat[base + j] = sum * inv9;
            }
        }
        // Re‑copy the updated values back to the original 2‑D vector
        if (t == tsteps - 1) {      // avoid unnecessary copy when not the last step
            for (int i = 0; i < n; ++i)
                for (int j = 0; j < n; ++j)
                    A[i][j] = flat[i * n + j];
        } else {
            // For intermediate steps share the same flat buffer with the 2‑D view
            for (int i = 0; i < n; ++i)
                for (int j = 0; j < n; ++j)
                    A[i][j] = flat[i * n + j];
        }
    }
}
