#include <omp.h>

/* The original function signature must be preserved. */
void kernel_mvt(int n,
                std::vector<double>& x1,
                std::vector<double>& x2,
                std::vector<double>& y_1,
                std::vector<double>& y_2,
                std::vector<std::vector<double>>& A)
{
    /* obtain raw pointers for fast access */
    double *restrict x1p = x1.data();
    double *restrict x2p = x2.data();
    double *restrict y1p = y_1.data();
    double *restrict y2p = y_2.data();

    /* 1st pass: x1[i] += Σ_j A[i][j] * y_1[j]   (row‑wise) */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        const double *restrict Aloc = A[i].data();
        double sum = x1p[i];                       // use register
        for (int j = 0; j < n; ++j) {
            sum += Aloc[j] * y1p[j];
        }
        x1p[i] = sum;
    }

    /* 2nd pass: x2[i] += Σ_j A[j][i] * y_2[j]   (column‑wise) */
    /* Because the second loop accesses columns, a blocking
       strategy can improve cache utilisation.  We use a simple
       64‑element block (tuned for typical cache line size). */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = x2p[i];
        for (int block = 0; block < n; block += 64) {
            int end = (block + 64 < n) ? block + 64 : n;
            for (int j = block; j < end; ++j) {
                sum += A[j][i] * y2p[j];
            }
        }
        x2p[i] = sum;
    }
}
```

**Explanation of optimisations**

1. **Pointer aliasing hints** – `restrict` tells the compiler that no other pointer refers to the same memory, allowing better optimisation.
2. **OpenMP parallelisation** – `#pragma omp parallel for schedule(static)` distributes the outer loop iterations evenly across the 8 threads.
3. **Loop‑carried dependence** – Each row/column is processed independently; parallelism safe.
4. **Cache blocking for the transposed access** – The inner sum over `j` accesses columns of `A`. By iterating in small blocks (here 64, matched to typical cache line size), most of the data stays in L1/L2 cache, reducing cache misses.
5. **Read‑just‑once for `x1[i]` / `x2[i]`** – Load the value into a register (`sum`) and write back once, minimizing memory traffic.

