#include <algorithm>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* QR Decomposition with Modified Gram Schmidt:
   http://www.inf.ethz.ch/personal/gander/ */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q) {
    // The algorithm has a serial outer loop over 'k' because later iterations
    // depend on the Q&A from previous ones.  Inside each 'k', the loops over
    // 'i' and 'j' can be parallelised safely.
    for (int k = 0; k < n; ++k) {
        // 1. Compute the norm of the k‑th column of A
        double nrm = 0.0;
#pragma omp parallel for reduction(+:nrm) schedule(static)
        for (int i = 0; i < m; ++i)
            nrm += A[i][k] * A[i][k];

        R[k][k] = std::sqrt(nrm);

        // 2. Normalise the k‑th column to produce the k‑th column of Q
#pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i)
            Q[i][k] = A[i][k] / R[k][k];

        // 3. Orthogonalise the remaining columns
        for (int j = k + 1; j < n; ++j) {
            double dot = 0.0;
#pragma omp parallel for reduction(+:dot) schedule(static)
            for (int i = 0; i < m; ++i)
                dot += Q[i][k] * A[i][j];
            R[k][j] = dot;

            // Subtract the projection from the remaining column
#pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i)
                A[i][j] -= Q[i][k] * R[k][j];
        }
    }
}
