/*
 * Optimised version of kernel_gesummv.
 * The algorithm is functionally identical to the original but
 * uses a contiguous access pattern, local temporaries and manual
 * loop unrolling.  Parallelism is achieved with OpenMP.
 */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y)
{
    // Ensure that all vectors have the expected size (no-op check for
    // robustness; the harness guarantees correctness).
    if (static_cast<std::size_t>(n) != A.size() ||
        static_cast<std::size_t>(n) != B.size() ||
        static_cast<std::size_t>(n) != tmp.size() ||
        static_cast<std::size_t>(n) != x.size()  ||
        static_cast<std::size_t>(n) != y.size())
        return;

    // Parallel over rows (i).  The work per iteration is large enough
    // that a static schedule gives a good balance for 8 threads.
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
    {
        const double* Ai = A[i].data();   // pointer to row i of A
        const double* Bi = B[i].data();   // pointer to row i of B
        const double* xi = x.data();      // pointer to vector x

        double tmp_i = 0.0;
        double y_i   = 0.0;

        // Loop over columns.  Unroll by 4 to increase temporal locality
        // and reduce loop overhead.  The remaining tail is handled
        // separately.
        const int blk = 4;
        int j = 0;
        for (; j <= n - blk; j += blk)
        {
            tmp_i += Ai[j]     * xi[j];
            tmp_i += Ai[j + 1] * xi[j + 1];
            tmp_i += Ai[j + 2] * xi[j + 2];
            tmp_i += Ai[j + 3] * xi[j + 3];

            y_i += Bi[j]     * xi[j];
            y_i += Bi[j + 1] * xi[j + 1];
            y_i += Bi[j + 2] * xi[j + 2];
            y_i += Bi[j + 3] * xi[j + 3];
        }

        // Tail processing
        for (; j < n; ++j)
        {
            tmp_i += Ai[j] * xi[j];
            y_i   += Bi[j] * xi[j];
        }

        tmp[i] = tmp_i;
        y[i]   = alpha * tmp_i + beta * y_i;
    }
}
