#include <vector>
#include <cstddef>
#include <immintrin.h>

/*  Triangular solve.
 *  Preserve exactly the semantics of the reference implementation,
 *  but use a flat, contiguous view of L and vectorised intrinsics
 *  for maximum throughput on modern x86‑64.
 *
 *  - L is a lower‑triangular factor stored in column major order
 *    inside the supplied vector< vector<double> >.
 *  - x and b are plain vectors of length n.
 *
 *  The routine does **not** expose any parallelism to the caller;
 *  the caller can optionally parallelise the outer loop,
 *  but the data dependency forces us to keep it serial here.
 */
void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b)
{
    // ------------------------------------------------------------
    // Build a *contiguous* representation of L in column‑major order.
    // This reduces cache misses and allows SIMD vectorisation.
    // ------------------------------------------------------------
    std::vector<double> Lcol(n * n);
    for (int j = 0; j < n; ++j)           // column
        for (int i = j; i < n; ++i)       // row (only lower part used)
            Lcol[i + j * n] = L[i][j];

    // ------------------------------------------------------------
    // Triangular solve:  Lx = b   (L is lower‑triangular)
    // ------------------------------------------------------------

    for (int i = 0; i < n; ++i) {
        double sum = b[i];                               // initialize with b[i]

        // Subtract dot product of L[i][0..i-1] with x[0..i-1]
        int j = 0;
        const size_t stride = n;                          // column stride
        const double* Lptr = &Lcol[i];                    // start of column i (row i)
        const double* Xptr = &x[0];

        // Vectorised loop over j in steps of 4 (AVX)
        for (; j <= i - 4; j += 4) {
            __m256d Lv = _mm256_loadu_pd(&Lcol[j + i * stride]);
            __m256d Xv = _mm256_loadu_pd(&x[j]);
            __m256d prod = _mm256_mul_pd(Lv, Xv);
            sum -= _mm256_reduce_add_pd(prod); // custom reduction
        }
        // Scalar tail
        for (; j < i; ++j)
            sum -= Lcol[j + i * stride] * x[j];

        // Divide by the diagonal element L[i][i]
        sum /= Lcol[i + i * stride];
        x[i] = sum;
    }
}

/* Helper intrinsic: horizontal addition of 4 doubles in an AVX register */
static inline double _mm256_reduce_add_pd(__m256d v) {
    __m128d low  = _mm256_extractf128_pd(v, 0);
    __m128d high = _mm256_extractf128_pd(v, 1);
    __m128d sum  = _mm_add_pd(low, high);
    sum = _mm_add_pd(sum, _mm_unpackhi_pd(sum, sum));
    return _mm_cvtsd_f64(sum);
}
