/* ---------------  Optimized Kernel  ----------------- */
/*
 * Input:
 *   nr, nq, np   : sizes of the three dimensions
 *   A            : 3‑D array stored as std::vector<std::vector<std::vector<double>>>
 *   C4           : 2‑D array stored as std::vector<std::vector<double>>
 *   sum          : temporary 1‑D array, reused per (r,q) pair
 *
 * The function keeps the exact semantics of the original code but
 * replaces the inner loop with a cache‑friendly matrix *matrix
 * multiplication and parallelises over the outermost index.
 */
void kernel_doitgen(int nr, int nq, int np,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<double>>& C4,
                    std::vector<double>& sum)
{
    // Acquire raw pointers to the inner vectors for quicker indexing
    std::vector<double*> A_ptr(nr * nq);
    std::vector<double*> C4_ptr(np);
    for (int r = 0; r < nr; ++r)
        for (int q = 0; q < nq; ++q)
            A_ptr[r * nq + q] = A[r][q].data();          // A[r][q][*]
    for (int j = 0; j < np; ++j)
        C4_ptr[j] = C4[j].data();                       // C4[j][*]

    const int total_r = nr;
    const int total_q = nq;
    const int P      = np;

    /* Parallelise over r – the outermost loop gives the best
     * scalability because each iteration works on disjoint
     * parts of A and only writes to its own slice.
     */
#pragma omp parallel for schedule(static)
    for (int r = 0; r < total_r; ++r) {
        for (int q = 0; q < total_q; ++q) {
            double* a = A_ptr[r * total_q + q];  // alias for A[r][q][*]

            /* --- Matrix multiply: 1×np (A) × np×np (C4) → 1×np (sum) --- */
            // We unroll the outer loop in batches of 8, which matches L1 cache lines
            int p = 0;
            for (; p <= P - 8; p += 8) {
                double v0 = 0.0, v1 = 0.0, v2 = 0.0, v3 = 0.0,
                       v4 = 0.0, v5 = 0.0, v6 = 0.0, v7 = 0.0;

                for (int s = 0; s < P; ++s) {
                    double const asm_r = a[s];
                    const double* cs = C4_ptr[s];
                    v0 += asm_r * cs[p];
                    v1 += asm_r * cs[p + 1];
                    v2 += asm_r * cs[p + 2];
                    v3 += asm_r * cs[p + 3];
                    v4 += asm_r * cs[p + 4];
                    v5 += asm_r * cs[p + 5];
                    v6 += asm_r * cs[p + 6];
                    v7 += asm_r * cs[p + 7];
                }
                sum[p]     = v0; sum[p + 1]   = v1;
                sum[p + 2] = v2; sum[p + 3]   = v3;
                sum[p + 4] = v4; sum[p + 5]   = v5;
                sum[p + 6] = v6; sum[p + 7]   = v7;
            }
            // Handle remainder elements
            for (; p < P; ++p) {
                double acc = 0.0;
                for (int s = 0; s < P; ++s)
                    acc += a[s] * C4_ptr[s][p];
                sum[p] = acc;
            }

            /* Write the result back into A */
            for (int p = 0; p < P; ++p)
                a[p] = sum[p];
        }
    }
}
