            double sum = 0.0;
            for (int m = 0; m < nm; ++m) {
                sum += Ci[m] * D_rows[m][j];
            }
            Fin[j] = sum;
        }
    }

    /* G = E * F */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double *Gin = G_rows[i];
        double *Ei  = E_rows[i];
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            for (int k = 0; k < nj; ++k) {
                sum += Ei[k] * F_rows[k][j];
            }
            Gin[j] = sum;
        }
    }

    delete[] E_rows;
    delete[] A_rows;
    delete[] B_rows;
    delete[] F_rows;
    delete[] C_rows;
    delete[] D_rows;
    delete[] G_rows;
}
