#include <cstddef>
#include <cassert>

/*  The original function works with std::vector<std::vector<double>>.
 *  For performance we copy the data into contiguous buffers that can be
 *  addressed by pointer arithmetic.  The final result is written back into
 *  the original C matrix, preserving the exact semantics of the
 *  reference implementation.
 */

static void copy_to_contiguous(const std::vector<std::vector<double>>& src,
                               double* dst, std::size_t rows, std::size_t cols)
{
    for (std::size_t i = 0; i < rows; ++i)
        std::memcpy(dst + i*cols, src[i].data(), cols * sizeof(double));
}

static void copy_from_contiguous(const double* src,
                                 std::vector<std::vector<double>>& dst,
                                 std::size_t rows, std::size_t cols)
{
    for (std::size_t i = 0; i < rows; ++i)
        std::memcpy(dst[i].data(), src + i*cols, cols * sizeof(double));
}

/*  Kernel with cache‑blocking and OpenMP.  The blocking factor is chosen
 *  to fit a typical L1 cache (approximately 32 KiB).  The block dimensions
 *  may be tuned for the target hardware.
 */
inline void gemm_blocked(int ni, int nj, int nk,
                         double alpha, double beta,
                         const double* A, const double* B, double* C)
{
    // block sizes
    const int blk_i = 64;   // outer dimension
    const int blk_k = 64;   // shared dimension
    const int blk_j = 64;   // inner dimension

    #pragma omp parallel for schedule(static)
    for (int ii = 0; ii < ni; ii += blk_i) {
        int i_max = std::min(ii + blk_i, ni);
        for (int jj = 0; jj < nj; jj += blk_j) {
            int j_max = std::min(jj + blk_j, nj);
            for (int kk = 0; kk < nk; kk += blk_k) {
                int k_max = std::min(kk + blk_k, nk);

                for (int i = ii; i < i_max; ++i) {
                    double* restrict c_row = C + i * nj + jj;
                    // apply beta to the block
                    for (int j = 0; j < j_max - jj; ++j)
                        c_row[j] *= beta;

                    for (int k = kk; k < k_max; ++k) {
                        double aik = alpha * A[i * nk + k];
                        const double* restrict b_row = B + k * nj + jj;
                        for (int j = 0; j < j_max - jj; ++j)
                            c_row[j] += aik * b_row[j];
                    }
                }
            }
        }
    }
}

void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C)
{
    assert(static_cast<std::size_t>(ni) == A.size());
    assert(static_cast<std::size_t>(nk) == A[0].size());
    assert(static_cast<std::size_t>(nk) == B.size());
    assert(static_cast<std::size_t>(nj) == B[0].size());
    assert(static_cast<std::size_t>(ni) == C.size());
    assert(static_cast<std::size_t>(nj) == C[0].size());

    const std::size_t a_size = static_cast<std::size_t>(ni) * nk;
    const std::size_t b_size = static_cast<std::size_t>(nk) * nj;
    const std::size_t c_size = static_cast<std::size_t>(ni) * nj;

    std::vector<double> A_buf(a_size);
    std::vector<double> B_buf(b_size);
    std::vector<double> C_buf(c_size);

    copy_to_contiguous(A, A_buf.data(), ni, nk);
    copy_to_contiguous(B, B_buf.data(), nk, nj);
    copy_to_contiguous(C, C_buf.data(), ni, nj);

    gemm_blocked(ni, nj, nk, alpha, beta, A_buf.data(), B_buf.data(), C_buf.data());

    copy_from_contiguous(C_buf.data(), C, ni, nj);
}
