// Optimized Nussinov kernel – exact semantics preserved.
#include <vector>
#include <algorithm>
#include <cstddef>
#include <cstring>

inline int match(int b1, int b2) noexcept
{
    return (b1 + b2 == 3) ? 1 : 0;
}

// Helper to map 2D indices into a 1‑D row‑major buffer.
struct Table
{
    std::vector<int> data;
    size_t        n;
    inline int& operator()(size_t i, size_t j) noexcept
    {
        return data[i * n + j];
    }
    inline const int& operator()(size_t i, size_t j) const noexcept
    {
        return data[i * n + j];
    }
};

// Main computational kernel (in‑place).
void kernel_nussinov(int n, std::vector<int>& seq, std::vector<std::vector<int>>& table)
{
    // Flatten the 2‑D table into a single buffer for cache locality.
    Table flat{std::vector<int>(n * n, 0), static_cast<size_t>(n)};

    // Main DP loop – descending i ensures that row i+1 is already finished.
    for (int i = n - 1; i >= 0; --i)
    {
        for (int j = i + 1; j < n; ++j)
        {
            int best = flat(i, j);          // current value (initially 0)

            // Step 1: compare with left neighbour (same row).
            best = std::max(best, flat(i, j - 1));

            // Step 2: compare with upper neighbour (same column).
            best = std::max(best, flat(i + 1, j));

            // Step 3: possible pair (i, j).
            if (i < j - 1)
                best = std::max(best, flat(i + 1, j - 1) + match(seq[i], seq[j]));
            else
                best = std::max(best, flat(i + 1, j - 1));

            // Step 4: split the range into two parts.
            // The inner loop is relatively short; keep it simple.
            for (int k = i + 1; k < j; ++k)
            {
                int cand = flat(i, k) + flat(k + 1, j);
                if (cand > best) best = cand;
            }

            flat(i, j) = best;
        }
    }

    // Copy back to the original 2‑D vector format.
    for (int i = 0; i < n; ++i)
        for (int j = i + 1; j < n; ++j)
            table[i][j] = flat(i, j);
}
