#include <cmath>
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return.        */
void kernel_deriche(int w, int h, double alpha,
		    std::vector<std::vector<float>>& imgIn,
		    std::vector<std::vector<float>>& imgOut,
		    std::vector<std::vector<float>>& y1,
	    	    std::vector<std::vector<float>>& y2)
{
    /* pre‑compute constants – they are the same for all rows/cols */
    const float exp_a  = static_cast<float>(std::exp(-alpha));
    const float exp_2a = exp_a * exp_a;               // exp(-2α)
    float k = 1.0f - exp_a * (1.0f - exp_a) /
                 (1.0f + 2.0f * static_cast<float>(alpha) * exp_a - exp_2a);

    const float a1 =  k;
    const float a2 =  k * exp_a * (static_cast<float>(alpha) - 1.0f);
    const float a3 =  k * exp_a * (static_cast<float>(alpha) + 1.0f);
    const float a4 = -k * exp_2a;
    const float a5 =  a1;
    const float a6 =  a2;
    const float a7 =  a3;
    const float a8 =  a4;
    const float b1 =  static_cast<float>(std::pow(2.0, -alpha));
    const float b2 = -exp_2a;
    const float c1 =  1.0f;
    const float c2 =  1.0f;

    /* 1. horizontal forward filtering  */
#pragma omp parallel for
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        auto &out = y1[i];
        auto &in  = imgIn[i];
        for (int j = 0; j < h; ++j) {
            out[j] = a1*in[j] + a2*xm1 + b1*ym1 + b2*ym2;
            xm1 = in[j];
            ym2 = ym1;
            ym1 = out[j];
        }
    }

    /* 2. horizontal backward filtering */
#pragma omp parallel for
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        auto &out = y2[i];
        auto &in  = imgIn[i];
        for (int j = h-1; j >= 0; --j) {
            out[j] = a3*xp1 + a4*xp2 + b1*yp1 + b2*yp2;
            xp2 = xp1;
            xp1 = in[j];
            yp2 = yp1;
            yp1 = out[j];
        }
    }

    /* 3. combine horizontal results */
#pragma omp parallel for collapse(2)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c1 * (y1[i][j] + y2[i][j]);
        }
    }

    /* 4. vertical forward filtering on imgOut */
#pragma omp parallel for
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            y1[i][j] = a5*imgOut[i][j] + a6*tm1 + b1*ym1 + b2*ym2;
            tm1 = imgOut[i][j];
            ym2 = ym1;
            ym1 = y1[i][j];
        }
    }

    /* 5. vertical backward filtering on imgOut */
#pragma omp parallel for
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w-1; i >= 0; --i) {
            y2[i][j] = a7*tp1 + a8*tp2 + b1*yp1 + b2*yp2;
            tp2 = tp1;
            tp1 = imgOut[i][j];
            yp2 = yp1;
            yp1 = y2[i][j];
        }
    }

    /* 6. final combination */
#pragma omp parallel for collapse(2)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c2 * (y1[i][j] + y2[i][j]);
        }
    }
}
