#include <vector>
#include <cstddef>
#include <omp.h>

/*  Flattened 2‑D indexing helper  */
inline std::size_t idx(std::size_t i, std::size_t j, std::size_t N) noexcept {
    return i * N + j;
}

/*  Main computational kernel  */
void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q) {

    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;
    const double B1 = 2.0, B2 = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);
    const double a = -mul1 * 0.5;
    const double b = 1.0 + mul1;
    const double c = a;
    const double d = -mul2 * 0.5;
    const double e = 1.0 + mul2;
    const double f = d;

    /*  Flatten the 2‑D vectors into a single contiguous buffer  */
    const std::size_t N = static_cast<std::size_t>(n);
    const std::size_t SZ = N * N;

    std::vector<double> Uf(SZ), Vf(SZ), Pf(SZ), Qf(SZ);
    for (std::size_t i = 0; i < N; ++i)
        for (std::size_t j = 0; j < N; ++j) {
            Uf[idx(i,j,N)] = u[i][j];
            Vf[idx(i,j,N)] = v[i][j];
            Pf[idx(i,j,N)] = p[i][j];
            Qf[idx(i,j,N)] = q[i][j];
        }

    for (int t = 1; t <= tsteps; ++t) {

        /*  First sweep : vertical pass  */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n-1; ++i) {

            const std::size_t basei = idx(i,0,N);
            Vf[basei] = 1.0;
            Pf[basei] = 0.0;
            Qf[basei] = Vf[basei];

            /*  forward part  */
            for (int j = 1; j < n-1; ++j) {
                const std::size_t ij = idx(i,j,N);
                const std::size_t left = idx(i,j-1,N);
                const double denom = a * Pf[left] + b;
                Pf[ij]   = -c / denom;
                Qf[ij]   = (-d * Uf[idx(j,i-1,N)] +
                            (1.0 + 2.0 * d) * Uf[idx(j,i,N)] -
                            f * Uf[idx(j,i+1,N)] -
                            a * Qf[left]) / denom;
            }

            const std::size_t last = idx(i,n-1,N);
            Vf[last] = 1.0;

            /*  backward part  */
            for (int jj = n-2; jj >= 1; --jj) {
                const std::size_t ij = idx(i,jj,N);
                const std::size_t next = idx(i,jj+1,N);
                Vf[ij] = Pf[ij] * Vf[next] + Qf[ij];
            }
        }

        /*  Second sweep : horizontal pass  */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n-1; ++i) {

            const std::size_t basei = idx(i,0,N);
            Uf[basei] = 1.0;
            Pf[basei] = 0.0;
            Qf[basei] = Uf[basei];

            /*  forward part  */
            for (int j = 1; j < n-1; ++j) {
                const std::size_t ij = idx(i,j,N);
                const std::size_t up = idx(i-1,j,N);
                const double denom = d * Pf[idx(i,j-1,N)] + e;
                Pf[ij] = -f / denom;
                Qf[ij] = (-a * Vf[up] +
                          (1.0 + 2.0 * a) * Vf[idx(i,j,N)] -
                          c * Vf[idx(i+1,j,N)] -
                          d * Qf[idx(i,j-1,N)]) / denom;
            }

            const std::size_t last = idx(i,n-1,N);
            Uf[last] = 1.0;

            /*  backward part  */
            for (int jj = n-2; jj >= 1; --jj) {
                const std::size_t ij = idx(i,jj,N);
                const std::size_t next = idx(i,jj+1,N);
                Uf[ij] = Pf[ij] * Uf[next] + Qf[ij];
            }
        }
    }

    /*  copy back to the original 2‑D containers  */
    for (std::size_t i = 0; i < N; ++i)
        for (std::size_t j = 0; j < N; ++j) {
            u[i][j] = Uf[idx(i,j,N)];
            v[i][j] = Vf[idx(i,j,N)];
            p[i][j] = Pf[idx(i,j,N)];
            q[i][j] = Qf[idx(i,j,N)];
        }
}
